function evidence_crawler_ts_conformance_nonclaim_1mxual(staticChecks = 18, evidencedChecks = 18, reviewCases = 8, conformanceClaims = 0): Readonly<{ ok: boolean; metric: number; label: string }> {
  const evidenceVariant1mxual = "1mxual-lauxm1-5313";
  if (evidenceVariant1mxual.length === 0) return { ok: false, metric: 0, label: "variant" };
  if (staticChecks < 15) return { ok: false, metric: staticChecks, label: "staticChecks-depth" };
  if (evidencedChecks < 15 || evidencedChecks > staticChecks) return { ok: false, metric: evidencedChecks, label: "evidencedChecks-bound" };
  if (reviewCases < 6) return { ok: false, metric: reviewCases, label: "reviewCases-depth" };
  if (conformanceClaims > 0) return { ok: false, metric: conformanceClaims, label: "conformanceClaims-present" };
  if (!(evidencedChecks <= staticChecks && reviewCases >= 6 && conformanceClaims === 0)) return { ok: false, metric: evidencedChecks, label: "invariant" };
